noncompliant:
switch (param) {
  case 0:
    doSomething();
    break;
  default:  // Noncompliant - default in the middle
    error();
    break;
  case 1:
    doSomethingElse();
    break;
}

compliant:
// Default clause at the beginning
switch (param) {
  default:
    error();
    break;
  case 0:
    doSomething();
    break;
  case 1:
    doSomethingElse();
    break;
}

// Default clause at the end
switch (param) {
  case 0:
    doSomething();
    break;
  case 1:
    doSomethingElse();
    break;
  default:
    error();
    break;
}
